import { cache } from 'react';

import type { Comment, Post } from '@/app/lib/types';

const JSON_PLACEHOLDER_BASE_URL = 'https://jsonplaceholder.typicode.com';

export const getRecentPosts = cache(async (): Promise<Post[]> => {
  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}/posts?_limit=5`, {
    cache: 'no-store',
  });

  if (!response.ok) {
    throw new Error('Failed to fetch recent posts.');
  }

  return (await response.json()) as Post[];
});

export const getAllPosts = cache(async (): Promise<Post[]> => {
  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}/posts`, {
    next: { revalidate: 60 },
  });

  if (!response.ok) {
    throw new Error('Failed to fetch posts.');
  }

  return (await response.json()) as Post[];
});

export const getPostById = cache(async (id: string): Promise<Post | null> => {
  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}/posts/${id}`, {
    next: { revalidate: 300 },
  });

  if (response.status === 404) {
    return null;
  }

  if (!response.ok) {
    throw new Error(`Failed to fetch post ${id}.`);
  }

  return (await response.json()) as Post;
});

export const getCommentsByPostId = cache(async (id: string): Promise<Comment[]> => {
  const response = await fetch(`${JSON_PLACEHOLDER_BASE_URL}/posts/${id}/comments`, {
    next: { revalidate: 300 },
  });

  if (!response.ok) {
    throw new Error(`Failed to fetch comments for post ${id}.`);
  }

  return (await response.json()) as Comment[];
});
